import { azureDevOpsCourse } from './azure-devops';

export const remainingC = [
  { id: 'aws', title: 'AWS', description: 'Amazon Web Services — the largest cloud platform.',
    officialDocs: 'https://docs.aws.amazon.com/', tutorialLink: 'https://aws.amazon.com/getting-started/', exerciseLink: null,
    sections: [
      { title: 'What is AWS', image: '/images/aws/service-landscape.svg', content: `Amazon Web Services is the world's largest public cloud platform and a foundational skill for modern infrastructure work. It provides compute, storage, databases, networking, security, observability, analytics, and machine learning services that can be combined to build almost any kind of system.\n\nA useful way to understand AWS is by capability areas rather than memorizing service names. Compute services run workloads, storage and database services persist data, networking connects systems securely, IAM controls access, and operations services help teams monitor and automate production environments.\n\nFor beginners, the goal is not to learn every AWS service. The goal is to understand the mental model well enough to choose the right class of service: VM, container, serverless function, object storage, managed database, or CDN.`, keyPoints: ['AWS is a broad platform, but most learning starts with compute, storage, networking, IAM, and observability.', 'Think in capability areas before memorizing service catalogs.', 'Choosing the right service model matters more than learning every product name.', 'AWS is widely used across startups, enterprises, and platform teams.'] },
      { title: 'Accounts, Regions & Availability Zones', content: `AWS is organized around accounts, regions, and availability zones. An AWS account is the security and billing boundary. A region is a geographic area such as us-east-1 or eu-west-1. Inside each region are multiple availability zones, which are isolated data center groupings designed for high availability.\n\nThis structure matters because architecture decisions are often really placement decisions. You choose where workloads run, where data is replicated, and how traffic fails over when one zone or one component has a problem.\n\nA strong beginner rule is simple: treat the AWS account as the security boundary, the region as the deployment location, and multiple availability zones as the baseline for production resilience.`, keyPoints: ['Accounts separate billing, IAM boundaries, and environments.', 'Regions determine latency, residency, and service availability.', 'Availability Zones help design for fault tolerance.', 'Production systems should usually avoid depending on one single zone.'] },
      { title: 'Compute Choices: EC2, Lambda, ECS & EKS', content: `AWS gives several ways to run applications. EC2 gives maximum control because you manage the virtual machine. Lambda removes server management and runs code only when events occur. ECS and EKS run containers, with ECS being AWS-native and EKS providing managed Kubernetes.\n\nA good learning approach is to compare them by operational burden. EC2 gives the most control but also the most maintenance. Lambda minimizes infrastructure management but requires event-driven design and attention to cold starts, time limits, and stateless execution. Containers sit in the middle: portable and scalable, but they require image building, service definitions, and deployment orchestration.\n\nTeams should choose the smallest operational model that still fits the workload. That rule prevents over-engineering.`, code: `# Common AWS CLI checks\naws sts get-caller-identity\naws ec2 describe-instances\naws ecs list-clusters\naws lambda list-functions\n\n# EC2 launch sketch\naws ec2 run-instances \\\n  --image-id ami-xxxxxxxx \\\n  --instance-type t3.micro \\\n  --count 1`, codeLabel: 'AWS Compute Basics', keyPoints: ['Use EC2 when you need VM-level control.', 'Use Lambda for event-driven and bursty workloads.', 'Use ECS or EKS when the workload is container-centric.', 'Operational burden is one of the best service-selection criteria.'] },
      { title: 'Storage and Database Services', content: `S3 is the core storage service in AWS and one of the first services every cloud learner should understand. It stores objects rather than files on a normal disk, which makes it ideal for static assets, backups, logs, exports, media, and data lakes. CloudFront often sits in front of S3 to cache content closer to users.\n\nFor databases, AWS separates managed relational systems from NoSQL. RDS and Aurora handle SQL engines such as PostgreSQL and MySQL while removing much of the patching, backup, and replication work. DynamoDB is the low-latency NoSQL option for key-value and document-oriented patterns.\n\nThe decision is not relational versus non-relational as an abstract debate. It is about access patterns, query shapes, scaling characteristics, and operational expectations.`, code: `# S3 static site deployment\naws s3 sync ./dist s3://my-course-site --delete\n\n# Terraform example\nresource "aws_s3_bucket" "assets" {\n  bucket = "my-learning-assets"\n}\n\nresource "aws_db_instance" "app_db" {\n  engine            = "postgres"\n  instance_class    = "db.t3.micro"\n  allocated_storage = 20\n}`, codeLabel: 'Storage & Database Examples', keyPoints: ['S3 is fundamental for static assets, backups, logs, and data lakes.', 'RDS and Aurora cover managed relational databases.', 'DynamoDB fits key-value and high-throughput NoSQL patterns.', 'Choose data services based on access patterns, not only popularity.'] },
      { title: 'Networking, IAM & Security Foundations', image: '/images/aws/network-security.svg', content: `Networking and security are where AWS starts to feel like real infrastructure engineering. The VPC defines the private network boundary. Subnets divide that network into zones such as public and private. Load balancers expose selected entry points. Security groups and network ACLs control traffic flow.\n\nIAM is equally important because it controls who can do what. Users, roles, policies, and temporary credentials form the access model. In production systems, IAM roles should be preferred over long-lived access keys because roles reduce secret sprawl and make access easier to rotate and audit.\n\nThe best beginner habit is to design with least privilege from the start. That habit matters more than any single security service.`, keyPoints: ['VPC, subnets, route tables, and load balancers define network structure.', 'Security groups are the first line of traffic control for many workloads.', 'IAM roles are safer than embedding access keys in code or servers.', 'Least privilege should be a default design rule, not an afterthought.'] },
      { title: 'Serverless Request Flow', image: '/images/aws/serverless-flow.svg', content: `One of the clearest AWS learning patterns is a small serverless system. A request reaches Route 53 and API Gateway, Lambda handles the business logic, and the function writes to DynamoDB or S3 depending on whether the workload needs structured state or object storage. CloudWatch then captures logs, metrics, and alarms.\n\nThis pattern is useful because it teaches several important AWS ideas at once: managed entry points, event-driven compute, pay-per-use pricing, observability, and separation between request handling and data persistence.\n\nIt also forces good discipline. Lambda functions should be stateless, fast to start, and focused on one small unit of responsibility.`, code: `exports.handler = async (event) => {\n  const name = JSON.parse(event.body ?? '{}').name ?? 'student';\n\n  return {\n    statusCode: 200,\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({ message: 'Hello, ' + name + ' from AWS Lambda' }),\n  };\n};`, codeLabel: 'Simple Lambda Handler', keyPoints: ['A serverless path often starts with DNS and API Gateway.', 'Lambda should stay stateless and small in scope.', 'DynamoDB and S3 are common persistence layers in serverless designs.', 'CloudWatch is essential for understanding behavior in production.'] },
      { title: 'Deployment, IaC & Observability', content: `Production AWS work should be automated. CloudFormation, CDK, Terraform, and CI/CD systems turn infrastructure and deployment steps into versioned code instead of manual console activity. That improves repeatability, reviewability, and disaster recovery.\n\nObservability is the parallel discipline. CloudWatch gives metrics, logs, dashboards, and alarms. CloudTrail records account-level API activity. Together they answer two operational questions: what changed, and how is the system behaving right now?\n\nTeams that automate infrastructure but ignore observability still struggle in production. The best systems invest in both.`, code: `resource "aws_cloudwatch_log_group" "api" {\n  name              = "/aws/lambda/student-api"\n  retention_in_days = 14\n}\n\nresource "aws_cloudwatch_metric_alarm" "lambda_errors" {\n  alarm_name          = "student-api-errors"\n  comparison_operator = "GreaterThanThreshold"\n  evaluation_periods  = 1\n  metric_name         = "Errors"\n  namespace           = "AWS/Lambda"\n  period              = 300\n  statistic           = "Sum"\n  threshold           = 1\n}`, codeLabel: 'Observability as Code', keyPoints: ['Use infrastructure as code instead of manual console-only setup.', 'CloudWatch handles metrics, logs, alarms, and dashboards.', 'CloudTrail provides account-level audit history.', 'Reliable delivery depends on both automation and observability.'] },
      { title: 'Best Practices for Learning AWS', content: `The fastest AWS learning path is to build two or three small architectures rather than reading long service lists. A strong sequence is: deploy a static site with S3 and CloudFront, build a simple API with API Gateway and Lambda, then run a small app on EC2 or containers so you can compare operational models directly.\n\nFocus on service-selection questions. Ask why one workload belongs on EC2 rather than Lambda, why one dataset belongs in RDS rather than DynamoDB, and why one app should be in a private subnet rather than public. Those decisions teach real cloud thinking.\n\nKeep your habits disciplined from the beginning: use IAM roles, separate environments, tag resources clearly, and clean up experiments so costs stay controlled.`, keyPoints: ['Learn AWS by building small architectures end to end.', 'Compare service models instead of studying each service in isolation.', 'Use IAM roles, tagging, and environment separation from the start.', 'Cost awareness is part of cloud engineering, not a later concern.'] }
    ]
  },
  { id: 'gcp', title: 'GCP', description: 'Google Cloud Platform — built on Google infrastructure.',
    officialDocs: 'https://cloud.google.com/docs', tutorialLink: 'https://cloud.google.com/docs/get-started', exerciseLink: null,
    sections: [
      { title: 'What is GCP', image: '/images/gcp/platform-overview.svg', content: `Google Cloud Platform runs on the same global infrastructure that powers Google services such as Search, YouTube, and Gmail. It is especially strong in analytics, managed Kubernetes, networking, and modern serverless container deployment.\n\nGCP becomes easier to understand when you start with its resource model. Projects are the main working boundary for APIs, IAM, quotas, and billing. Around that, organizations and folders help larger companies structure teams and environments.\n\nFor learners, GCP stands out because many services are opinionated in a helpful way. Cloud Run, BigQuery, and managed load balancing often let teams move quickly with less infrastructure management than they expected.`, keyPoints: ['GCP is strong in analytics, Kubernetes, networking, and serverless containers.', 'Projects are the main boundary for IAM, billing, APIs, and quotas.', 'Many GCP services are designed to reduce infrastructure management.', 'Understanding the resource hierarchy makes the rest of the platform much easier.'] },
      { title: 'Projects, IAM & Resource Hierarchy', content: `GCP organizes resources using organizations, folders, and projects. Most hands-on work happens inside a project, which acts as the container for services, service accounts, quotas, logging, and billing relationships.\n\nIAM then decides who can act inside that structure. Roles can be primitive, predefined, or custom, and they are assigned to users, groups, or service accounts. Service accounts matter because workloads should usually authenticate as an identity with limited permissions instead of sharing user credentials.\n\nA good beginner habit is to think in boundaries. Projects define where things live, and IAM defines who can operate them.`, code: `# Authenticate and inspect context\ngcloud auth login\ngcloud config list\n\ngcloud projects list\ngcloud projects describe my-learning-project\n\ngcloud iam service-accounts list \\\n  --project my-learning-project`, codeLabel: 'Project and IAM Basics', keyPoints: ['Projects are the main unit of work in GCP.', 'IAM roles should be granted as narrowly as possible.', 'Service accounts are the preferred identity for workloads.', 'Resource hierarchy matters more as teams and environments grow.'] },
      { title: 'Runtime Choices: Compute Engine, Cloud Run & GKE', image: '/images/gcp/runtime-choices.svg', content: `GCP gives several ways to run workloads, and each one represents a different operational contract. Compute Engine gives VM-level control. Cloud Run lets teams deploy a container without managing servers and can scale down to zero. GKE provides managed Kubernetes when a team needs advanced orchestration, service meshes, or many coordinated services.\n\nThis is one of the most important design choices in GCP because it shapes team workload. Compute Engine is powerful but operationally heavier. Cloud Run is often the fastest way to ship modern APIs and background handlers. GKE is excellent for platform-scale container orchestration, but it carries more complexity than smaller teams usually need at the start.\n\nA strong default for new web APIs is to evaluate Cloud Run first, then move to VMs or Kubernetes only when a real technical reason appears.`, code: `# Deploy containerized app to Cloud Run\ngcloud run deploy course-api \\\n  --source . \\\n  --region us-central1 \\\n  --allow-unauthenticated\n\n# Create a small VM\ngcloud compute instances create learning-vm \\\n  --zone us-central1-a \\\n  --machine-type e2-micro\n\n# Create a GKE cluster\ngcloud container clusters create learning-cluster \\\n  --num-nodes=2 \\\n  --zone=us-central1-a`, codeLabel: 'GCP Runtime Commands', keyPoints: ['Compute Engine gives maximum VM control.', 'Cloud Run is a strong default for containerized APIs and small services.', 'GKE is powerful but should be chosen deliberately, not by default.', 'Runtime choice should be based on operational burden as well as features.'] },
      { title: 'Storage, Databases & Analytics', image: '/images/gcp/data-analytics.svg', content: `GCP is unusually strong when data and analytics are central to the system. Cloud Storage handles object storage. Cloud SQL provides managed relational databases. Firestore offers a document model for application data. BigQuery provides serverless analytical querying at warehouse scale. Pub/Sub and Dataflow often connect ingestion and transformation pipelines.\n\nThis combination explains why GCP appears so often in analytics-heavy environments. Teams can ingest events, process data streams, store raw files, and query massive datasets without building large amounts of custom platform machinery.\n\nThe right lesson for beginners is not just that BigQuery is fast. It is that GCP makes analytical system design feel more native and less bolted on.`, keyPoints: ['Cloud Storage handles objects, backups, and raw datasets.', 'Cloud SQL and Firestore serve different application data patterns.', 'Pub/Sub and Dataflow support event ingestion and transformation.', 'BigQuery is a major reason teams choose GCP for data-heavy workloads.'] },
      { title: 'Networking, Security & Service Accounts', content: `GCP networking has a distinctive global flavor. VPC networks are global resources, subnets are regional, and Google-managed load balancing can distribute traffic across large geographic scopes. This model is different from AWS and worth learning directly rather than assuming all clouds structure networking the same way.\n\nOn the security side, IAM and service accounts are central. Workloads should authenticate with service accounts, secrets should be stored in Secret Manager, and auditability should come from Cloud Logging, Cloud Monitoring, and policy controls rather than manual trust.\n\nA productive beginner rule is this: do not mix identity, connectivity, and authorization mentally. They are related, but each needs explicit design.`, keyPoints: ['GCP VPC design differs from AWS and should be learned on its own terms.', 'Service accounts are the preferred workload identity model.', 'Secret Manager is better than hardcoding secrets in repos or startup scripts.', 'Good cloud security starts with explicit boundaries and auditable access.'] },
      { title: 'CI/CD, Infrastructure as Code & Operations', content: `Cloud Build, Artifact Registry, and Terraform are common building blocks for delivery on GCP. Cloud Build handles automated build steps, Artifact Registry stores container images and packages, and Terraform or deployment tools describe infrastructure in versioned code.\n\nOperationally, Cloud Logging and Cloud Monitoring provide the main visibility layer. Alerts, dashboards, uptime checks, and error budgets turn cloud resources into an actual operated system rather than a pile of deployed services.\n\nThe key lesson is the same as on every cloud: a successful platform is not only about deploying code. It is about reliable change, clear ownership, and fast incident understanding.`, code: `steps:\n- name: 'gcr.io/cloud-builders/docker'\n  args: ['build', '-t', 'us-central1-docker.pkg.dev/my-project/apps/course-api:latest', '.']\n- name: 'gcr.io/cloud-builders/docker'\n  args: ['push', 'us-central1-docker.pkg.dev/my-project/apps/course-api:latest']\n- name: 'gcr.io/google.com/cloudsdktool/cloud-sdk'\n  entrypoint: gcloud\n  args: ['run', 'deploy', 'course-api', '--image', 'us-central1-docker.pkg.dev/my-project/apps/course-api:latest', '--region', 'us-central1']`, codeLabel: 'Cloud Build to Cloud Run', keyPoints: ['Cloud Build automates builds and deployments.', 'Artifact Registry stores deployable images and packages.', 'Terraform keeps GCP infrastructure reviewable and repeatable.', 'Logging and monitoring are first-class operational requirements.'] },
      { title: 'Best Practices for Learning GCP', content: `The best way to learn GCP is to build around its strengths. A useful progression is: deploy a container to Cloud Run, store assets in Cloud Storage, add identity with a service account, then build a small data path using Pub/Sub and BigQuery so the analytics story becomes concrete.\n\nFocus on choices that are uniquely instructive in GCP: why Cloud Run may be better than a VM, why BigQuery changes reporting architecture, and how project and IAM boundaries shape safe collaboration.\n\nKeep your practice grounded. Use separate projects for experiments, avoid over-privileged roles, and make sure every workload identity and deployment path is explainable.`, keyPoints: ['Learn GCP by using Cloud Run, Cloud Storage, IAM, and BigQuery together.', 'Use separate projects for clear environment boundaries.', 'Prefer least privilege and workload identities from the start.', 'Study the platform through architecture choices, not only command syntax.'] }
    ]
  },
  azureDevOpsCourse,
  { id: 'data-structure', title: 'Data Structures', description: 'Organizing data for efficient access and modification.',
    officialDocs: null, tutorialLink: 'https://www.w3schools.com/dsa/', exerciseLink: 'https://leetcode.com/',
    sections: [
      { title: 'What are Data Structures', image: '/images/data-structures/ds-overview.svg', content: `**Data structures** define how data is *organized*, *stored*, and *accessed* in memory. Choosing the right data structure dramatically affects application performance — the difference between \`O(1)\` and \`O(n)\` lookups can mean **milliseconds vs minutes**.\n\n### Linear Structures\n\n**Linear structures** store data sequentially: **Arrays**, **Linked Lists**, **Stacks**, **Queues**. Elements have a clear *before* and *after* relationship and are traversed in a single run.\n\n### Non-Linear Structures\n\n**Non-linear structures** store data hierarchically or relationally: **Trees**, **Graphs**, **Hash Maps**, **Heaps**. These structures enable faster search, flexible relationships, and efficient priority handling.\n\nEvery data structure is a trade-off between **time complexity** (how fast) and **space complexity** (how much memory). [Big-O notation](https://en.wikipedia.org/wiki/Big_O_notation) is the standard framework for measuring these trade-offs.`, keyPoints: ['Right structure = fast app, wrong structure = slow app.', 'Linear: Arrays, Linked Lists, Stacks, Queues.', 'Non-linear: Trees, Graphs, Hash Maps, Heaps.', 'Big-O notation measures time/space complexity.'] },
      { title: 'Arrays & Linked Lists', content: `**Arrays** store elements *contiguously in memory*. Access by index is \`O(1)\`, but insertion/deletion in the middle is \`O(n)\` because elements must shift. Use arrays when you need **fast random access**.\n\n### When to Use Arrays\n\nArrays are ideal for *indexed access*, *iteration*, and situations where the size is relatively stable. JavaScript's \`Array\`, Python's \`list\`, and Java's \`ArrayList\` are all array-backed structures.\n\n### Linked Lists\n\n**Linked Lists** store elements as nodes with pointers. Insertion/deletion is \`O(1)\` if you have a reference to the node, but access by index is \`O(n)\` because you must traverse. Use when you need **frequent insertions/deletions** at the head or middle without shifting elements.\n\nVariations include **singly linked** (one direction), **doubly linked** (both directions), and **circular linked** (tail points back to head).`, code: `// Array — O(1) access, O(n) insertion\nconst arr = [10, 20, 30, 40];\narr[2];          // O(1) — instant access\narr.splice(1, 0, 15); // O(n) — shift elements\n\n// Linked List — O(1) insert, O(n) access\nclass Node {\n  constructor(val) { this.val = val; this.next = null; }\n}\nclass LinkedList {\n  constructor() { this.head = null; }\n  prepend(val) {  // O(1)\n    const node = new Node(val);\n    node.next = this.head;\n    this.head = node;\n  }\n  find(val) {  // O(n)\n    let curr = this.head;\n    while (curr) {\n      if (curr.val === val) return curr;\n      curr = curr.next;\n    }\n    return null;\n  }\n}`, codeLabel: 'Array vs Linked List', keyPoints: ['Array: O(1) read, O(n) insert/delete.', 'Linked List: O(1) insert/delete, O(n) read.', 'Arrays for random access, lists for frequent mutations.'] },
      { title: 'Stacks, Queues & Hash Maps', content: `### Stack (LIFO)\n\n**Stack** (*Last In, First Out*): Think of a stack of plates. \`push()\` adds to top, \`pop()\` removes from top. Used for **undo functionality**, **function call stacks**, **bracket matching**, and *backtracking algorithms*.\n\n### Queue (FIFO)\n\n**Queue** (*First In, First Out*): Think of a line at a store. \`enqueue()\` adds to back, \`dequeue()\` removes from front. Used for **task scheduling**, **BFS traversal**, **message queues**, and *printer spooling*.\n\n### Hash Map\n\n**Hash Map** (\`O(1)\` average lookup): Maps keys to values using a **hash function**. JavaScript's \`Map\` and \`Object\`, Python's \`dict\`, Java's \`HashMap\`. Used for **caching**, **counting frequencies**, and **fast lookups**. Collisions are handled via *chaining* or *open addressing*.`, code: `// Stack (LIFO)\nconst stack = [];\nstack.push("A"); stack.push("B"); stack.push("C");\nstack.pop();  // "C" (last in, first out)\n\n// Queue (FIFO)\nconst queue = [];\nqueue.push("A"); queue.push("B"); queue.push("C");\nqueue.shift(); // "A" (first in, first out)\n\n// Hash Map — O(1) lookups\nconst wordCount = new Map();\nconst words = ["hello", "world", "hello", "js"];\nfor (const w of words) {\n  wordCount.set(w, (wordCount.get(w) || 0) + 1);\n}\n// Map { "hello" => 2, "world" => 1, "js" => 1 }`, codeLabel: 'Stacks, Queues & Hash Maps', keyPoints: ['Stack: LIFO — undo, call stacks, backtracking.', 'Queue: FIFO — scheduling, BFS, message processing.', 'Hash Map: O(1) key-value lookups.', 'Choose based on access pattern: LIFO, FIFO, or key-based.'] },
      { title: 'Trees & Big-O Notation', content: `**Trees** are hierarchical structures with a **root node** and **child nodes**. **Binary Search Trees** (BST) maintain order: left children are *smaller*, right children are *larger*. This enables \`O(log n)\` search, insert, and delete.\n\n### Balanced Trees\n\n**AVL trees** and **Red-Black trees** are *self-balancing* BSTs that guarantee \`O(log n)\` operations by automatically restructuring after insertions and deletions. **Heaps** are complete binary trees used for *priority queues* — a **min-heap** always gives the smallest element in \`O(1)\`.\n\n### Big-O Notation\n\n**Big-O Notation** measures how performance scales with input size: \`O(1)\` *constant*, \`O(log n)\` *logarithmic*, \`O(n)\` *linear*, \`O(n log n)\` *linearithmic*, \`O(n²)\` *quadratic*. Always aim for the lowest complexity. Understanding Big-O is essential for [technical interviews](https://leetcode.com/) and writing performant code.`, code: `// Binary Search Tree\nclass TreeNode {\n  constructor(val) {\n    this.val = val;\n    this.left = null;\n    this.right = null;\n  }\n}\nclass BST {\n  constructor() { this.root = null; }\n  insert(val, node = this.root) {\n    if (!this.root) { this.root = new TreeNode(val); return; }\n    if (val < node.val) {\n      if (!node.left) node.left = new TreeNode(val);\n      else this.insert(val, node.left);\n    } else {\n      if (!node.right) node.right = new TreeNode(val);\n      else this.insert(val, node.right);\n    }\n  }\n}\n\n// Big-O Cheat Sheet\n// O(1)      — Hash Map lookup\n// O(log n)  — Binary Search, BST operations\n// O(n)      — Linear search, single loop\n// O(n log n) — Merge Sort, Quick Sort\n// O(n²)     — Nested loops (Bubble Sort)`, codeLabel: 'BST & Big-O', keyPoints: ['BST: O(log n) search, insert, delete.', 'O(1) < O(log n) < O(n) < O(n log n) < O(n²).', 'Use balanced trees (AVL, Red-Black) to guarantee O(log n).', 'Always analyze complexity before choosing an algorithm.'] },
      { title: 'Graphs & Traversal Algorithms', content: `**Graphs** represent *relationships between entities* — social networks, maps, dependency trees, and web page links are all graph problems. A graph consists of **vertices** (nodes) and **edges** (connections).\n\n### Graph Types\n\n**Directed graphs** have one-way edges (like Twitter follows). **Undirected graphs** have two-way edges (like Facebook friendships). **Weighted graphs** assign costs to edges (like road distances). Graphs can be stored as an **adjacency list** (space-efficient for *sparse* graphs) or an **adjacency matrix** (fast lookups for *dense* graphs).\n\n### Traversal Algorithms\n\n**BFS** (*Breadth-First Search*) explores level by level using a **queue** — ideal for finding the *shortest path* in unweighted graphs. **DFS** (*Depth-First Search*) explores as deep as possible using a **stack** or recursion — ideal for *cycle detection*, *topological sorting*, and finding *connected components*.`, code: `// Graph as Adjacency List\nconst graph = {\n  A: ["B", "C"],\n  B: ["A", "D"],\n  C: ["A", "E"],\n  D: ["B"],\n  E: ["C"]\n};\n\n// BFS — Breadth-First Search (Queue)\nfunction bfs(graph, start) {\n  const visited = new Set();\n  const queue = [start];\n  visited.add(start);\n  while (queue.length > 0) {\n    const node = queue.shift();\n    console.log(node);\n    for (const neighbor of graph[node]) {\n      if (!visited.has(neighbor)) {\n        visited.add(neighbor);\n        queue.push(neighbor);\n      }\n    }\n  }\n}\n\n// DFS — Depth-First Search (Recursion)\nfunction dfs(graph, node, visited = new Set()) {\n  visited.add(node);\n  console.log(node);\n  for (const neighbor of graph[node]) {\n    if (!visited.has(neighbor)) {\n      dfs(graph, neighbor, visited);\n    }\n  }\n}\n\nbfs(graph, "A"); // A, B, C, D, E\ndfs(graph, "A"); // A, B, D, C, E`, codeLabel: 'Graph Traversal', keyPoints: ['Graphs model relationships: social networks, maps, dependencies.', 'BFS explores level-by-level — ideal for shortest path.', 'DFS explores depth-first — ideal for cycle detection.', 'Adjacency list for sparse, adjacency matrix for dense graphs.'] },
      { title: 'Sorting Algorithms & Complexity', content: `Sorting is one of the most fundamental operations in computer science. Choosing the right sorting algorithm depends on **data size**, **data characteristics**, and **memory constraints**.\n\n### Simple Sorts — O(n²)\n\n**Bubble Sort** repeatedly swaps adjacent elements — simple but *inefficient*. **Selection Sort** finds the minimum and places it at the front. **Insertion Sort** builds the sorted array one item at a time — efficient for *nearly sorted* data and small datasets.\n\n### Efficient Sorts — O(n log n)\n\n**Merge Sort** divides the array in half, sorts each half, and merges — *stable* and *predictable* but uses \`O(n)\` extra space. **Quick Sort** picks a *pivot* and partitions elements — \`O(n log n)\` average but \`O(n²)\` worst case. **Heap Sort** uses a **binary heap** for in-place sorting.\n\n### Choosing the Right Sort\n\nMost languages use **Timsort** (Python, Java) or **Introsort** (C++) — hybrid algorithms that combine the best properties of multiple sorts. For [competitive programming](https://leetcode.com/), understanding *when each sort excels* matters more than memorizing implementations.`, code: `// Merge Sort — O(n log n), stable\nfunction mergeSort(arr) {\n  if (arr.length <= 1) return arr;\n  const mid = Math.floor(arr.length / 2);\n  const left = mergeSort(arr.slice(0, mid));\n  const right = mergeSort(arr.slice(mid));\n  return merge(left, right);\n}\nfunction merge(left, right) {\n  const result = [];\n  let i = 0, j = 0;\n  while (i < left.length && j < right.length) {\n    if (left[i] <= right[j]) result.push(left[i++]);\n    else result.push(right[j++]);\n  }\n  return [...result, ...left.slice(i), ...right.slice(j)];\n}\n\n// Quick Sort — O(n log n) average\nfunction quickSort(arr) {\n  if (arr.length <= 1) return arr;\n  const pivot = arr[arr.length - 1];\n  const left = arr.filter((x, i) => x <= pivot && i < arr.length - 1);\n  const right = arr.filter(x => x > pivot);\n  return [...quickSort(left), pivot, ...quickSort(right)];\n}\n\nconsole.log(mergeSort([38, 27, 43, 3, 9, 82, 10]));\n// [3, 9, 10, 27, 38, 43, 82]`, codeLabel: 'Sorting Algorithms', keyPoints: ['O(n²) sorts: Bubble, Selection, Insertion (small data only).', 'O(n log n) sorts: Merge Sort (stable), Quick Sort (fast average).', 'Merge Sort uses extra space; Quick Sort is in-place.', 'Most real runtimes use hybrid sorts like Timsort.'] }
    ]
  },
  { id: 'sys-arch', title: 'System Architecture', description: 'Designing scalable, reliable software systems.',
    officialDocs: null, tutorialLink: 'https://github.com/donnemartin/system-design-primer', exerciseLink: null,
    sections: [
      { title: 'Architecture Patterns', image: '/images/system-architecture/architecture-patterns.svg', content: `### Monolithic Architecture\n\n**Monolithic**: All code in one deployable unit. *Simple* to develop and deploy initially, but harder to scale and maintain as it grows. Teams must coordinate releases, and a bug in one module can crash the entire system.\n\n### Microservices Architecture\n\n**Microservices**: System split into small, independent services communicating via **APIs**. Each service is deployed, scaled, and maintained independently. Requires investment in *service discovery*, *distributed tracing*, and *inter-service communication*.\n\n### Event-Driven Architecture\n\n**Event-Driven**: Services communicate through events/messages (\`Kafka\`, \`RabbitMQ\`) rather than direct API calls. Enables **loose coupling** and *async processing*. Great for *real-time analytics*, *order processing*, and *notification systems*.\n\n### Serverless Architecture\n\n**Serverless**: Cloud provider manages infrastructure entirely. Deploy functions (*AWS Lambda*, *Azure Functions*) that **auto-scale** and charge per execution. Ideal for *event-driven*, *bursty workloads* with unpredictable traffic.`, keyPoints: ['Monolith: simple start, hard to scale.', 'Microservices: independent, scalable, complex.', 'Event-driven: loose coupling via message queues.', 'Serverless: zero infrastructure management.'] },
      { title: 'Scalability & Load Balancing', content: `**Vertical scaling** adds more power to one server (more CPU/RAM). **Horizontal scaling** adds more servers. Horizontal scaling is preferred because it has *no upper limit* and provides **redundancy**.\n\n### Load Balancing\n\n**Load balancers** distribute incoming traffic across multiple servers. Algorithms: *Round Robin*, *Least Connections*, *IP Hash*. **Health checks** automatically remove unhealthy servers from rotation. Popular tools include **Nginx**, **HAProxy**, and cloud-native ALBs.\n\n### Caching & CDNs\n\n**Caching** (\`Redis\`, \`Memcached\`) stores frequently accessed data in memory, reducing database load by orders of magnitude. **CDNs** (*Content Delivery Networks*) like **CloudFront** and **Cloudflare** cache static assets globally for faster delivery to users worldwide.`, keyPoints: ['Horizontal scaling > vertical scaling.', 'Load balancers distribute traffic across servers.', 'Caching reduces database load dramatically.', 'CDNs deliver static assets globally.'] },
      { title: 'CAP Theorem & Database Scaling', content: `The **CAP Theorem** states a distributed system can guarantee only **2 of 3**: **Consistency** (every read returns the latest write), **Availability** (every request gets a response), and **Partition Tolerance** (system works despite network failures).\n\n### Database Scaling Strategies\n\n**Read replicas** handle read traffic separately from writes — essential for *read-heavy* workloads. **Sharding** splits data across multiple database instances by a key (\`user_id\`, \`region\`). **Connection pooling** (\`PgBouncer\`, \`HikariCP\`) reuses database connections to prevent exhaustion.\n\n### Choosing the Right Strategy\n\nStart with **vertical scaling** and **read replicas** before introducing sharding complexity. Use **eventual consistency** where real-time accuracy isn't critical (analytics, feeds). Design for failure — assume *any component can crash at any time*.`, keyPoints: ['CAP: choose 2 of Consistency, Availability, Partition Tolerance.', 'Read replicas for scaling read-heavy workloads.', 'Sharding distributes data across multiple databases.', 'Design for failure — assume any component can crash.'] },
      { title: 'API Design & Communication Patterns', content: `### REST APIs\n\n**REST** (*Representational State Transfer*) is the most common API style. Resources are accessed via **HTTP methods**: \`GET\` (read), \`POST\` (create), \`PUT\` (update), \`DELETE\` (remove). Use *plural nouns* for endpoints: \`/api/users\`, \`/api/orders/:id\`. Return proper **HTTP status codes**: \`200\` success, \`201\` created, \`400\` bad request, \`404\` not found, \`500\` server error.\n\n### GraphQL\n\n**GraphQL** lets clients request *exactly the data they need* in a single query — no over-fetching or under-fetching. Ideal for *complex UIs* with varied data needs. Trade-off: more complex backend setup and caching.\n\n### gRPC & Message Queues\n\n**gRPC** uses *Protocol Buffers* for fast, strongly-typed service-to-service communication. **Message queues** (\`RabbitMQ\`, \`Kafka\`, \`SQS\`) enable **asynchronous communication** — the sender doesn't wait for the receiver. Essential for *decoupled*, *event-driven* architectures.`, code: `// REST API Design Example\nGET    /api/users          // List all users\nGET    /api/users/:id       // Get single user\nPOST   /api/users           // Create user\nPUT    /api/users/:id       // Update user\nDELETE /api/users/:id       // Delete user\n\n// Status Codes\n200 OK              // Successful read\n201 Created         // Successful create\n204 No Content      // Successful delete\n400 Bad Request     // Invalid input\n401 Unauthorized    // Not authenticated\n403 Forbidden       // Not authorized\n404 Not Found       // Resource doesn't exist\n429 Too Many Req    // Rate limited\n500 Internal Error  // Server error\n\n// GraphQL Query Example\nquery {\n  user(id: "123") {\n    name\n    email\n    orders {\n      total\n      status\n    }\n  }\n}`, codeLabel: 'API Design Patterns', keyPoints: ['REST: HTTP methods + plural nouns + status codes.', 'GraphQL: client-driven queries, no over-fetching.', 'gRPC: fast binary protocol for service-to-service.', 'Message queues enable async, decoupled communication.'] },
      { title: 'Monitoring, Reliability & Incident Response', content: `### Observability Pillars\n\nProduction systems need three pillars of observability: **Logs** (what happened), **Metrics** (how the system is performing), and **Traces** (request flow across services). Tools like *Prometheus*, *Grafana*, *Datadog*, and *ELK Stack* provide this visibility.\n\n### Reliability Engineering\n\n**SLOs** (*Service Level Objectives*) define target reliability — e.g., *99.9% uptime*. **Error budgets** balance reliability with feature velocity. **Circuit breakers** prevent cascading failures by stopping calls to failing services. **Retry with exponential backoff** handles transient errors gracefully.\n\n### Incident Response\n\nWhen systems fail: **detect** (alerts, dashboards), **respond** (on-call rotation, runbooks), **mitigate** (rollback, feature flags), **review** (blameless postmortems). Great teams invest in *automation*, *runbooks*, and *game days* to practice failure scenarios before they hit production.`, keyPoints: ['Three pillars: Logs, Metrics, Traces.', 'SLOs and error budgets balance reliability with velocity.', 'Circuit breakers prevent cascading failures.', 'Blameless postmortems improve systems, not blame people.'] }
    ]
  },
  { id: 'design-patterns', title: 'Design Patterns', description: 'Proven solutions to common software design problems.',
    officialDocs: null, tutorialLink: 'https://refactoring.guru/design-patterns', exerciseLink: null,
    sections: [
      { title: 'What are Design Patterns', image: '/images/design-patterns/design-patterns-overview.svg', content: `**Design patterns** are *reusable solutions* to commonly occurring problems in software design. Cataloged by the "**Gang of Four**" (GoF) in their seminal 1994 book, they provide a **shared vocabulary** for developers worldwide.\n\n### Three Categories\n\n**Creational** patterns control *how objects are created* — managing instantiation complexity. **Structural** patterns define *how objects are composed* — building flexible, efficient structures. **Behavioral** patterns govern *how objects interact* — enabling clean communication and responsibility sharing.\n\nPatterns are not code to copy-paste — they are **templates** that guide your design decisions. The key is recognizing *when a problem fits a pattern* rather than forcing patterns into every solution. See [Refactoring Guru](https://refactoring.guru/design-patterns) for visual explanations of all 23 classic patterns.`, keyPoints: ['Proven solutions, not code to copy-paste.', 'Three categories: Creational, Structural, Behavioral.', 'Gang of Four (GoF) cataloged 23 classic patterns.', 'Don\'t force patterns — use them when the problem fits.'] },
      { title: 'Creational Patterns', content: `### Singleton\n\n**Singleton**: Ensures only *one instance* of a class exists globally — commonly used for **database connection pools**, **loggers**, and **configuration managers**. Use sparingly because singletons introduce *global state* and make testing harder.\n\n### Factory Method\n\n**Factory Method**: Creates objects without specifying exact classes, using a *factory interface*. The client code works with the interface while the factory decides which concrete class to instantiate. Essential for *plugin systems* and *dependency injection*.\n\n### Builder\n\n**Builder**: Constructs complex objects step-by-step — especially useful when constructors have *many parameters*. Each method returns \`this\`, enabling **method chaining** for readable object construction.`, code: `// Singleton (Module pattern in JS)\nclass Database {\n  static #instance = null;\n  static getInstance() {\n    if (!Database.#instance) {\n      Database.#instance = new Database();\n    }\n    return Database.#instance;\n  }\n}\n\n// Factory\nclass NotificationFactory {\n  static create(type) {\n    switch(type) {\n      case 'email': return new EmailNotification();\n      case 'sms': return new SMSNotification();\n      case 'push': return new PushNotification();\n    }\n  }\n}\nconst notif = NotificationFactory.create('email');\n\n// Builder\nconst query = new QueryBuilder()\n  .select("name", "email")\n  .from("users")\n  .where("active = true")\n  .orderBy("name")\n  .build();`, codeLabel: 'Creational Patterns', keyPoints: ['Singleton: one global instance (use sparingly).', 'Factory: create objects without specifying exact class.', 'Builder: step-by-step complex object construction.'] },
      { title: 'Structural & Behavioral Patterns', content: `### Structural Patterns\n\n**Adapter**: Converts one interface into another that clients expect — like a *power adapter* for different countries. **Decorator**: Adds behavior to objects *dynamically* without modifying their code — middleware in Express.js is a decorator pattern. **Facade**: Provides a *simplified interface* to a complex subsystem — like a hotel concierge handling multiple departments.\n\n### Behavioral Patterns\n\n**Observer**: Objects subscribe to events and get notified when state changes — React state, \`EventEmitter\`, DOM events. **Strategy**: Defines a family of *interchangeable algorithms* — sorting strategies, payment methods, validation rules. **Command**: Encapsulates a request as an object — enables **undo/redo**, *macro recording*, and *request queuing*.`, code: `// Observer Pattern\nclass EventEmitter {\n  #listeners = {};\n  on(event, fn) {\n    (this.#listeners[event] ??= []).push(fn);\n  }\n  emit(event, data) {\n    this.#listeners[event]?.forEach(fn => fn(data));\n  }\n}\n\nconst bus = new EventEmitter();\nbus.on('userCreated', (user) => sendWelcomeEmail(user));\nbus.on('userCreated', (user) => logActivity(user));\nbus.emit('userCreated', { name: 'Alice' });\n\n// Strategy Pattern\nconst strategies = {\n  credit: (amount) => chargeCard(amount),\n  paypal: (amount) => paypalCheckout(amount),\n  crypto: (amount) => cryptoTransfer(amount),\n};\nfunction checkout(method, amount) {\n  return strategies[method](amount);\n}`, codeLabel: 'Structural & Behavioral', keyPoints: ['Observer: event-driven communication (pub/sub).', 'Strategy: interchangeable algorithms at runtime.', 'Adapter: make incompatible interfaces work together.', 'Decorator: add behavior without modifying original code.'] },
      { title: 'SOLID Principles', content: `The **SOLID** principles are five design guidelines that make software more *maintainable*, *flexible*, and *scalable*. They complement design patterns and are essential for **object-oriented design**.\n\n### The Five Principles\n\n**S — Single Responsibility**: A class should have *one reason to change*. Split classes that handle multiple concerns (e.g., separate data access from business logic).\n\n**O — Open/Closed**: Classes should be *open for extension* but *closed for modification*. Add new behavior through **inheritance** or **composition**, not by editing existing code.\n\n**L — Liskov Substitution**: Subtypes must be *substitutable* for their base types without breaking behavior. If it looks like a duck but needs batteries, you have the wrong abstraction.\n\n**I — Interface Segregation**: Many *small, focused interfaces* are better than one large interface. Clients should not depend on methods they don't use.\n\n**D — Dependency Inversion**: High-level modules should depend on *abstractions*, not concrete implementations. This enables **dependency injection** and easier testing.`, code: `// Single Responsibility — BEFORE (two concerns)\nclass UserService {\n  createUser(data) { /* save to DB */ }\n  sendWelcomeEmail(user) { /* send email */ }  // NOT its job\n}\n\n// Single Responsibility — AFTER (separated concerns)\nclass UserService {\n  createUser(data) { /* save to DB */ }\n}\nclass EmailService {\n  sendWelcomeEmail(user) { /* send email */ }\n}\n\n// Dependency Inversion — depend on abstractions\nclass OrderService {\n  constructor(paymentGateway) {  // injected\n    this.payment = paymentGateway;\n  }\n  checkout(order) {\n    this.payment.charge(order.total);  // works with ANY gateway\n  }\n}\n\n// Open/Closed — extend without modifying\nclass Discount {\n  calculate(price) { return price; }\n}\nclass SeasonalDiscount extends Discount {\n  calculate(price) { return price * 0.8; }  // 20% off\n}\nclass VIPDiscount extends Discount {\n  calculate(price) { return price * 0.7; }  // 30% off\n}`, codeLabel: 'SOLID Principles', keyPoints: ['Single Responsibility: one class, one reason to change.', 'Open/Closed: extend behavior without modifying existing code.', 'Liskov Substitution: subtypes must be interchangeable.', 'Dependency Inversion: depend on abstractions, not concretions.'] },
      { title: 'Patterns in Real Frameworks', content: `Design patterns are everywhere in popular frameworks and libraries. Recognizing them helps you *understand framework architecture* and write **idiomatic code**.\n\n### Frontend Patterns\n\n**React** uses the **Observer pattern** (state changes trigger re-renders), **Composite pattern** (component trees), and **Higher-Order Component** pattern (wrapping components to add behavior). **Redux** is a pure **Command pattern** — actions describe what happened, reducers decide how state changes.\n\n### Backend Patterns\n\n**Express.js** middleware is the **Chain of Responsibility** pattern — each middleware processes the request and passes it along. **Spring Boot** uses **Dependency Injection** (Inversion of Control), **Repository pattern** (data access abstraction), and **Proxy pattern** (\`@Transactional\`, \`@Cacheable\`).\n\n### Infrastructure Patterns\n\n**Docker** uses the **Builder pattern** (Dockerfile builds images step-by-step). **Kubernetes** uses the **Sidecar pattern** (auxiliary containers alongside main containers) and **Observer pattern** (controllers watch resource state). Understanding *which pattern a framework uses* helps you extend it correctly.`, keyPoints: ['React: Observer, Composite, Higher-Order Components.', 'Express middleware: Chain of Responsibility pattern.', 'Spring Boot: Dependency Injection, Repository, Proxy.', 'Recognizing patterns helps you extend frameworks correctly.'] }
    ]
  },
  { id: 'github', title: 'GitHub', description: 'World\'s largest platform for version control and collaboration.',
    officialDocs: 'https://docs.github.com/', tutorialLink: 'https://docs.github.com/en/get-started/quickstart', exerciseLink: null,
    sections: [
      { title: 'What is GitHub', content: `GitHub is a cloud-based platform for hosting Git repositories, enabling collaboration, code review, and project management. It hosts over 200 million repositories and is the center of open-source development.\n\nGit is a distributed version control system created by Linus Torvalds in 2005. It tracks every change made to your code, allowing you to revert to any previous state, compare changes over time, and collaborate with others without overwriting each other's work.\n\nGitHub adds a web-based layer on top of Git, providing a visual interface, Pull Requests for code review, Issues for tracking bugs and features, Projects for Kanban boards, Actions for CI/CD automation, Pages for free static site hosting, and Packages for artifact registries.\n\nEvery professional developer must know Git and GitHub. It is used by virtually every software company worldwide — from startups to enterprises like Google, Microsoft, Facebook, and Amazon.`, image: 'https://images.unsplash.com/photo-1618401471353-b98afee0b2eb?w=800&auto=format&fit=crop&q=60', keyPoints: ['200M+ repositories — the largest developer platform.', 'Git tracks every change — revert, compare, branch freely.', 'Pull Requests enable structured code review.', 'Issues + Projects for project management.', 'GitHub Actions for CI/CD automation.', 'GitHub Pages for free static website hosting.'] },
      { title: 'Git Installation & Setup', content: `Before using GitHub, you need to install Git on your local machine. Git is available for Windows, macOS, and Linux.\n\nStep 1: Visit https://git-scm.com/downloads and download the latest version for your operating system.\n\nStep 2: Run the installer. On Windows, accept the default settings (ensure "Git Bash" is included). On macOS, you can also install via Homebrew: brew install git. On Linux: sudo apt install git (Ubuntu/Debian) or sudo yum install git (CentOS/RHEL).\n\nStep 3: Verify the installation by opening a terminal and running git --version. You should see the installed version number.\n\nStep 4: Configure your identity. Git needs your name and email to tag every commit you make. This is essential for collaboration — your team sees who made each change.`, code: `# Download & Install Git\n# Visit: https://git-scm.com/downloads\n# Download for your OS and install\n\n# Verify installation\ngit --version\n# Output: git version 2.44.0\n\n# Configure your identity (REQUIRED)\ngit config --global user.name "Your Full Name"\ngit config --global user.email "your.email@company.com"\n\n# Verify configuration\ngit config --global --list\n# Output:\n# user.name=Your Full Name\n# user.email=your.email@company.com\n\n# Optional: Set default branch name to 'main'\ngit config --global init.defaultBranch main\n\n# Optional: Set VS Code as default editor\ngit config --global core.editor "code --wait"`, codeLabel: 'Git Installation & Configuration', keyPoints: ['Download Git from git-scm.com/downloads.', 'git config sets your name and email for commits.', 'Use --global flag to apply settings to all repositories.', 'Always verify with git --version after installation.'] },
      { title: 'Create GitHub Account', content: `To use GitHub, you need a free account. GitHub offers free unlimited public and private repositories.\n\nStep 1: Visit https://github.com and click "Sign Up."\n\nStep 2: Enter your email address (preferably your company/work email for professional repositories). Choose a username that is professional and recognizable — this becomes your public identity (e.g., github.com/yourusername).\n\nStep 3: Create a strong password and verify your email address. GitHub will send a verification code.\n\nStep 4: After verification, you will be taken to the dashboard. Note your username, email, and password — you will need them for Git configuration and authentication.\n\nStep 5: Set up Two-Factor Authentication (2FA) under Settings → Password and Authentication. This is highly recommended (and required for many organizations) for account security.\n\nGitHub Plans: Free (unlimited repos, 2000 Actions minutes/month), Team ($4/user/month — advanced collaboration), and Enterprise ($21/user/month — SSO, audit logs, compliance).`, keyPoints: ['Visit github.com and sign up with your email.', 'Choose a professional, recognizable username.', 'Enable Two-Factor Authentication (2FA) for security.', 'Free plan includes unlimited public and private repos.', 'Note your username, email, and password.'] },
      { title: 'Create a Repository', content: `A repository (repo) is a folder that Git tracks. It contains your project files, the entire change history, and branch information.\n\nCreate a New Repository on GitHub:\n1. Log in to github.com\n2. Click the "+" icon at the top right → "New repository"\n3. Enter a repository name (e.g., "developer-guide")\n4. Add an optional description\n5. Choose visibility: Public (anyone can see) or Private (only you and invited collaborators)\n6. Optionally initialize with a README, .gitignore, and license\n7. Click "Create repository"\n\nAfter creating the repository on GitHub, you'll see quick setup instructions showing how to connect a local project to this remote repository.`, code: `# === Option 1: Create a new repository from scratch ===\necho "# developer-guide" >> README.md\ngit init\ngit add README.md\ngit commit -m "first commit"\ngit branch -M main\ngit remote add origin https://github.com/antonyrobin/developer-guide.git\ngit push -u origin main\n\n# === Option 2: Push an existing local project ===\ngit remote add origin https://github.com/antonyrobin/developer-guide.git\ngit branch -M main\ngit push -u origin main\n\n# === Option 3: Clone an existing repository ===\ngit clone https://github.com/antonyrobin/developer-guide.git\ncd developer-guide`, codeLabel: 'Repository Creation Commands', keyPoints: ['git init initializes a new local Git repository.', 'git remote add origin connects local repo to GitHub.', 'git clone downloads an existing repo from GitHub.', 'Choose Public or Private visibility based on your needs.', '-M flag renames the default branch to main.'] },
      { title: 'Setup Repository Locally', content: `To work on a GitHub repository from your computer, you need to clone it or connect your local folder to the remote repository.\n\nCloning downloads the entire repository including all branches and history. Connecting an existing folder adds the remote URL so you can push/pull changes.\n\nAfter connecting, use git pull to download the latest code from the remote branch before starting your work. This ensures you have the most up-to-date code and prevents merge conflicts.`, code: `# Navigate to your projects directory\ncd /path/to/your/projects\n\n# Clone a repository (downloads everything)\ngit clone https://github.com/antonyrobin/developer-guide.git\ncd developer-guide\n\n# --- OR connect an existing folder ---\ncd my-existing-project\ngit init\ngit remote add origin https://github.com/antonyrobin/developer-guide.git\n\n# Switch to the development branch\ngit checkout -b development\n\n# Pull the latest code from remote\ngit pull origin development\n\n# Verify remote connection\ngit remote -v\n# Output:\n# origin  https://github.com/antonyrobin/developer-guide.git (fetch)\n# origin  https://github.com/antonyrobin/developer-guide.git (push)\n\n# See all branches (local + remote)\ngit branch -a`, codeLabel: 'Local Repository Setup', keyPoints: ['git clone downloads the full repo with history.', 'git remote add origin connects to a remote URL.', 'Always git pull before starting new work.', 'git remote -v verifies your remote connection.'] },
      { title: 'Add, Commit & Push Files', image: '/images/github-workflow.png', content: `The Git workflow follows three stages: Working Directory (your changes) → Staging Area (selected changes) → Repository (committed snapshot).\n\ngit add selects which changes to include in the next commit. git add . stages ALL changed files. git add filename stages a specific file.\n\ngit commit creates a permanent snapshot of the staged changes with a descriptive message. Commit messages should be clear and explain WHY the change was made, not just WHAT changed.\n\ngit push uploads your local commits to the remote GitHub repository. The first push to a new branch requires the -u flag (upstream tracking). After that, just git push is enough.\n\nCommit Message Best Practices: Use the conventional format: type: description. Types: feat (new feature), fix (bug fix), docs (documentation), style (formatting), refactor (code restructuring), test (tests), chore (maintenance).`, code: `# === Using Command Line ===\n\n# Stage all changed files\ngit add .\n\n# Stage specific file(s)\ngit add src/App.jsx src/index.css\n\n# Check what is staged\ngit status\n\n# Commit with a descriptive message\ngit commit -m "feat: add user authentication module"\n\n# Push to remote branch (first time)\ngit push -u origin username/dev\n\n# Push to remote branch (subsequent pushes)\ngit push\n\n# === Using IDE (VS Code) ===\n# 1. Select the correct branch (bottom-left corner)\n# 2. Pull latest changes (sync button)\n# 3. Make your code changes\n# 4. Open Source Control panel (Ctrl+Shift+G)\n# 5. Stage changes (+ icon next to files)\n# 6. Write commit message in the text box\n# 7. Click Commit, then Push\n\n# === Quick Commit Shortcut ===\n# Stage + Commit in one command\ngit commit -am "fix: resolve login redirect bug"`, codeLabel: 'Add, Commit & Push', keyPoints: ['git add . stages all changes for commit.', 'git commit -m creates a snapshot with a message.', 'git push uploads commits to GitHub.', 'Use conventional commit messages: feat:, fix:, docs:.', 'In VS Code: Source Control panel → Stage → Commit → Push.'] },
      { title: 'Push, Pull & Fetch', content: `These three commands manage data transfer between your local repository and the remote GitHub repository.\n\ngit push: Uploads your local commits to the remote repository. Only the current branch is pushed. If the remote has newer commits, push will be rejected — you must pull first.\n\ngit pull: Downloads AND merges remote changes into your current branch. It is equivalent to git fetch + git merge. Always pull before starting new work to avoid conflicts.\n\ngit fetch: Downloads remote changes but does NOT merge them. It updates your knowledge of the remote branches without changing your working code. Use this when you want to review changes before merging.\n\nCommon issue: "rejected — non-fast-forward." This means someone else pushed changes to the same branch. Solution: git pull first, resolve any conflicts, then git push again.`, code: `# Push local commits to remote\ngit push origin development\n\n# Pull latest changes from remote (fetch + merge)\ngit pull origin development\n\n# Fetch without merging (safe preview)\ngit fetch origin\ngit log origin/development  # See what changed\ngit merge origin/development # Then merge manually\n\n# Pull with rebase (cleaner history)\ngit pull --rebase origin development\n\n# Force push (DANGEROUS — only for your own branches)\ngit push --force origin username/dev\n\n# Push a new local branch to remote for the first time\ngit push -u origin feature/new-dashboard\n\n# See tracking relationship\ngit branch -vv`, codeLabel: 'Push, Pull & Fetch Commands', keyPoints: ['git push uploads local commits to remote.', 'git pull downloads AND merges remote changes.', 'git fetch downloads changes WITHOUT merging.', 'Always pull before push to avoid conflicts.', 'Never force push to shared branches (main, development).'] },
      { title: 'Branch Creation & Management', image: '/images/github-branching.png', content: `Branches let you work on features, fixes, or experiments without affecting the main codebase. Each branch is an independent line of development.\n\nCommon branching strategy:\n- main — Production-ready code. Only merged via Pull Requests.\n- development — Integration branch where features are combined.\n- feature/xyz — Individual feature branches created from development.\n- hotfix/xyz — Emergency fixes branched from main.\n\nNaming conventions: Use prefixes to categorize branches. Examples: feature/user-auth, bugfix/login-error, hotfix/security-patch, username/task-name.\n\nAlways create feature branches from the latest development branch. Never commit directly to main or development — always use Pull Requests.`, code: `# Create a new branch and switch to it\ngit checkout -b feature/user-auth\n\n# Same as above (modern syntax)\ngit switch -c feature/user-auth\n\n# Switch to an existing branch\ngit checkout development\ngit switch development\n\n# List all local branches\ngit branch\n\n# List all branches (local + remote)\ngit branch -a\n\n# Delete a local branch (after merge)\ngit branch -d feature/user-auth\n\n# Delete a remote branch\ngit push origin --delete feature/user-auth\n\n# Rename current branch\ngit branch -M new-branch-name\n\n# Create branch from development\ngit checkout development\ngit pull origin development\ngit checkout -b username/task-name`, codeLabel: 'Branch Commands', keyPoints: ['git checkout -b creates and switches to a new branch.', 'Always branch from the latest development code.', 'Use prefixes: feature/, bugfix/, hotfix/, username/.', 'Delete branches after they are merged.', 'Never commit directly to main or development.'] },
      { title: 'Pull Request Creation & Review', image: '/images/github-pr-flow.png', content: `A Pull Request (PR) is a request to merge your branch's changes into another branch (usually development or main). PRs enable code review, discussion, and quality control before changes are integrated.\n\nCreating a Pull Request:\n1. Push your branch to GitHub: git push -u origin username/dev\n2. Visit https://github.com and navigate to your repository\n3. Click the "Pull Requests" tab\n4. Click "New Pull Request"\n5. Select Base branch (development) and Compare branch (your branch)\n6. Write a clear title and description explaining your changes\n7. Click "Create Pull Request"\n\nPR Review Process:\n- Reviewers examine the code diff, leave comments, and suggest changes\n- "Approve" — Code is good to merge\n- "Request Changes" — Author must address feedback before merging\n- "Comment" — General feedback without approval or rejection\n\nAfter all reviewers approve and CI checks pass, the PR can be merged.`, code: `# Step 1: Push your branch to GitHub\ngit push -u origin username/dev\n\n# Step 2: Create PR on GitHub\n# Visit: https://github.com/your-repo\n# Click "Pull Requests" → "New Pull Request"\n# Select:\n#   Base: development  ←  Compare: username/dev\n# Write title & description\n# Click "Create Pull Request"\n\n# === OR create PR via GitHub CLI ===\ngh pr create \\\n  --base development \\\n  --title "feat: add user authentication" \\\n  --body "Implements login/logout with JWT tokens. Closes #42"\n\n# List open PRs\ngh pr list\n\n# View PR details\ngh pr view 15\n\n# Review a PR\ngh pr review 15 --approve\ngh pr review 15 --request-changes --body "Please add error handling"\n\n# Merge a PR\ngh pr merge 15 --squash`, codeLabel: 'Pull Request Workflow', keyPoints: ['Push your branch first, then create PR on GitHub.', 'Select Base (target) and Compare (your branch) branches.', 'Reviewers can Approve, Request Changes, or Comment.', 'All approvals + CI checks must pass before merging.', 'Use GitHub CLI (gh) for command-line PR management.'] },
      { title: 'Merge Pull Request', content: `After a PR is approved by reviewers and all CI checks pass, it can be merged. Merging integrates your branch's changes into the base branch.\n\nMerge Methods:\n- Merge Commit: Creates a merge commit preserving full branch history. Best for feature branches with meaningful commit history.\n- Squash and Merge: Compresses all branch commits into a single commit. Best for keeping a clean main branch history.\n- Rebase and Merge: Replays branch commits on top of the base branch. Creates a linear history without merge commits.\n\nMerging on GitHub:\n1. Visit https://github.com and go to your repository\n2. Click the "Pull Requests" tab\n3. Open the approved Pull Request\n4. Click "Merge Pull Request" (choose merge method)\n5. Click "Confirm Merge"\n6. You'll see "Pull Request successfully merged and closed"\n7. Optionally delete the source branch\n\nAfter merging, all team members should pull the latest changes from the base branch to stay in sync.`, code: `# === Merge on GitHub (Web UI) ===\n# 1. Go to repository → Pull Requests\n# 2. Open the approved PR\n# 3. Click "Merge Pull Request"\n# 4. Select merge method (Squash recommended)\n# 5. Click "Confirm Merge"\n# 6. Delete the source branch (cleanup)\n\n# === Merge via GitHub CLI ===\ngh pr merge 15 --squash --delete-branch\n\n# === After merge: Update your local ===\ngit checkout development\ngit pull origin development\n\n# === Resolve merge conflicts (if any) ===\ngit pull origin development\n# If conflicts appear:\n# 1. Open conflicting files\n# 2. Look for <<<< ==== >>>> markers\n# 3. Choose which changes to keep\n# 4. Remove conflict markers\n# 5. Stage and commit\ngit add .\ngit commit -m "fix: resolve merge conflicts"\ngit push`, codeLabel: 'Merge & Conflict Resolution', keyPoints: ['Squash and Merge creates clean single commits.', 'Delete the source branch after merging.', 'Always pull latest changes after a merge.', 'Resolve conflicts by editing the <<<< ==== >>>> markers.', 'git pull before starting new work prevents conflicts.'] },
      { title: 'Repository Visibility & Branch Rules', content: `Repository Visibility:\n- Public: Anyone on the internet can see this repository. You choose who can commit.\n- Private: Only you and explicitly invited collaborators can see and access this repository.\n- Internal (GitHub Enterprise): Visible to all org members but not the public.\n\nYou can change visibility anytime in Settings → General → Danger Zone.\n\nBranch Protection Rules protect critical branches (main, development) from direct pushes and force pushes. To set up:\n1. Go to repository Settings → Branches\n2. Click "Add branch protection rule"\n3. Enter branch name pattern (e.g., "main")\n4. Enable recommended rules:\n   - Require pull request reviews before merging\n   - Require status checks to pass (CI/CD)\n   - Require conversation resolution before merging\n   - Do not allow force pushes\n   - Do not allow deletions\n   - Require signed commits (optional, for high security)\n\nBranch rules ensure code quality by preventing unreviewed code from entering production.`, keyPoints: ['Public repos are visible to everyone; Private repos are restricted.', 'Branch Protection prevents direct pushes to main/development.', 'Require PR reviews before merging to protected branches.', 'Require CI status checks to pass before allowing merge.', 'Never allow force pushes or deletions on protected branches.'] },
      { title: 'Releases & Tags', content: `Releases are packaged versions of your software with release notes, changelogs, and downloadable assets. They are tied to Git tags, which mark specific points in your repository's history.\n\nTags are like bookmarks pointing to a specific commit. Semantic Versioning (SemVer) is the standard: v1.2.3 where 1 = major (breaking changes), 2 = minor (new features), 3 = patch (bug fixes).\n\nCreating a Release on GitHub:\n1. Go to your repository → "Releases" (right sidebar)\n2. Click "Draft a new release"\n3. Choose a tag (create new, e.g., v1.0.0)\n4. Set the target branch (usually main)\n5. Write a release title and description (changelog)\n6. Optionally upload binary assets (installers, packages)\n7. Click "Publish release"`, code: `# Create a tag locally\ngit tag v1.0.0\ngit tag -a v1.0.0 -m "Release version 1.0.0"\n\n# Push tag to GitHub\ngit push origin v1.0.0\n\n# Push all tags\ngit push origin --tags\n\n# List all tags\ngit tag -l\n\n# Delete a local tag\ngit tag -d v1.0.0\n\n# Delete a remote tag\ngit push origin --delete v1.0.0\n\n# Create release via GitHub CLI\ngh release create v1.0.0 \\\n  --title "Version 1.0.0" \\\n  --notes "Initial stable release with user auth and dashboard"`, codeLabel: 'Tags & Releases', keyPoints: ['Tags mark specific commits (versions) in history.', 'Use Semantic Versioning: vMAJOR.MINOR.PATCH.', 'Releases package your code with notes and downloads.', 'git push origin --tags pushes all tags to GitHub.'] },
      { title: 'Issues & Project Tracking', content: `Issues are GitHub's built-in bug/feature tracker. Every repository has an Issues tab where you can report bugs, request features, ask questions, and track tasks.\n\nCreating an Issue:\n1. Go to repository → Issues tab\n2. Click "New Issue"\n3. Write a clear title and detailed description\n4. Assign to a team member\n5. Add labels (bug, enhancement, documentation, etc.)\n6. Add to a Project board (optional)\n7. Set a milestone (e.g., "v1.0 Release")\n\nGitHub Projects provide Kanban-style boards for task management:\n1. Go to Projects tab → "New Project"\n2. Choose Board, Table, or Roadmap view\n3. Add Issues and Pull Requests as cards\n4. Create columns: To Do, In Progress, In Review, Done\n5. Drag cards between columns as work progresses\n6. Use filters and automation to auto-move cards\n\nProjects integrate directly with Issues and PRs — when a PR closes an issue (using "Closes #42" in the PR description), the linked card automatically moves to Done.`, keyPoints: ['Issues track bugs, features, and tasks.', 'Labels categorize issues (bug, enhancement, etc.).', 'Projects provide Kanban boards for visual tracking.', '"Closes #42" in PR descriptions auto-closes issues.', 'Milestones group issues into release targets.', 'Use @mentions to notify specific team members.'] },
      { title: 'Team Collaboration', content: `GitHub enables seamless team collaboration through repository access control, code reviews, and communication tools.\n\nAdding Collaborators:\n1. Repository Settings → Collaborators\n2. Click "Add people"\n3. Search by username or email\n4. Set role: Read (view only), Triage (manage issues), Write (push code), Maintain (manage settings), Admin (full access)\n\nOrganizations group repositories and team members under one account. Create teams (Frontend, Backend, DevOps) with different access levels across repositories.\n\nCollaboration Best Practices:\n- Always create feature branches — never work directly on main.\n- Write clear commit messages with context.\n- Keep Pull Requests small and focused (one feature per PR).\n- Review others' code promptly and constructively.\n- Use Draft PRs for work-in-progress that needs early feedback.\n- Reference Issues in commits and PRs for traceability.\n- Pull the latest changes from the base branch before pushing.\n- Resolve all review comments before requesting re-review.`, code: `# Daily collaboration workflow\n\n# 1. Start your day — pull latest changes\ngit checkout development\ngit pull origin development\n\n# 2. Create your feature branch\ngit checkout -b username/feature-name\n\n# 3. Do your work, commit frequently\ngit add .\ngit commit -m "feat: add search functionality"\n\n# 4. Push to remote\ngit push -u origin username/feature-name\n\n# 5. Create Pull Request on GitHub\n# Title: "feat: add search functionality"\n# Description: "Implements course search with filtering. Closes #15"\n# Assign reviewers\n# Link to Issue\n\n# 6. Address review feedback\ngit add .\ngit commit -m "fix: address review comments"\ngit push\n\n# 7. After approval and merge — cleanup\ngit checkout development\ngit pull origin development\ngit branch -d username/feature-name`, codeLabel: 'Daily Collaboration Workflow', keyPoints: ['Add collaborators with appropriate access roles.', 'Use Organizations to group repos and team members.', 'Create feature branches for every change.', 'Keep PRs small, focused, and well-described.', 'Review code promptly and constructively.', 'Pull latest changes before starting new work.'] }
    ]
  },
  { id: 'github-actions', title: 'GitHub Actions', description: 'Automate CI/CD workflows with YAML directly in GitHub.',
    officialDocs: 'https://docs.github.com/en/actions', tutorialLink: 'https://docs.github.com/en/actions/quickstart', exerciseLink: null,
    sections: [
      { title: 'What are GitHub Actions', image: '/images/github-actions/workflow-anatomy.svg', content: `GitHub Actions is GitHub's built-in automation platform for CI, CD, release workflows, repository maintenance, and pull request quality checks. Workflows live in .github/workflows so the automation is versioned with the application code.\n\nThe key mental model is event to workflow to jobs to steps. An event starts the workflow, jobs run on runners, and each job executes steps that either use existing actions or run shell commands.`, keyPoints: ['Automation is stored in the repository with the code.', 'The core structure is event, workflow, job, and step.', 'Actions can handle CI, CD, review automation, and maintenance tasks.', 'Versioned automation is easier to review and debug.'] },
      { title: 'YAML, Trigger Events, Inputs, and Secrets', image: '/images/github-actions/triggers-and-pr.svg', content: `Every workflow is a YAML file. The most important keys are name, on, jobs, env, permissions, and concurrency. YAML indentation matters, so many workflow bugs come from structure mistakes instead of logic mistakes.\n\nTrigger events decide when workflows run. Common ones are push, pull_request, workflow_dispatch, schedule, release, and workflow_call. Inputs are especially useful with workflow_dispatch because they let you choose values like target environment or image tag when the workflow starts.\n\nUse variables for normal configuration and secrets for sensitive values such as tokens and credentials. Also reduce GITHUB_TOKEN permissions so each workflow gets only the access it actually needs.`, code: `name: Pull Request Validation\n\non:\n  pull_request:\n    branches: [main, development]\n  workflow_dispatch:\n    inputs:\n      target_env:\n        description: 'Environment to deploy'\n        required: true\n        type: choice\n        options: [dev, stage, prod]\n\npermissions:\n  contents: read\n  pull-requests: write\n\njobs:\n  validate:\n    runs-on: ubuntu-latest\n    steps:\n    - uses: actions/checkout@v4\n    - run: npm ci\n    - run: npm test\n    - run: echo Deploying to \${{ inputs.target_env }}\n      env:\n        API_TOKEN: \${{ secrets.DEPLOY_API_TOKEN }}`, codeLabel: 'YAML, Events, Inputs, and Secrets', keyPoints: ['Choose trigger events based on workflow risk and cost.', 'workflow_dispatch inputs make manual workflows reusable.', 'Secrets should hold sensitive values only.', 'Minimal token permissions are a security best practice.'] },
      { title: 'Docker, Linux and Windows, Self-Hosted Runners, Approvals, Review Automation, and Coverage', image: '/images/github-actions/runners-and-matrix.svg', content: `Docker is one of the most common GitHub Actions use cases. A workflow can build an image, tag it with the commit SHA, push it to a registry, and then deploy that same immutable artifact.\n\nGitHub-hosted runners support Linux, Windows, and macOS. Matrix strategy helps validate across operating systems or runtime versions. Self-hosted runners are useful when you need private network access, custom software, or internal deployment access, but they also add maintenance responsibility.\n\nGitHub Environments let teams model dev, stage, and prod with separate secrets and approval rules. Actions can also automate PR quality checks such as linting, test execution, coverage reports, required checklist validation, and comment automation so human reviewers can focus on risk and design.`, code: `jobs:\n  docker-test:\n    strategy:\n      matrix:\n        os: [ubuntu-latest, windows-latest]\n    runs-on: \${{ matrix.os }}\n    steps:\n    - uses: actions/checkout@v4\n    - uses: docker/login-action@v3\n      with:\n        registry: ghcr.io\n        username: \${{ github.actor }}\n        password: \${{ secrets.GITHUB_TOKEN }}\n    - uses: docker/build-push-action@v6\n      with:\n        push: true\n        tags: ghcr.io/my-org/my-app:\${{ github.sha }}\n\n  deploy-prod:\n    needs: docker-test\n    runs-on: ubuntu-latest\n    environment: prod\n    steps:\n    - run: echo Deploying after approval`, codeLabel: 'Docker, Runners, and Approvals', keyPoints: ['Use Docker images as the deployable artifact.', 'Validate on Windows when platform differences matter.', 'Use self-hosted runners only when requirements justify them.', 'Automate PR checks, coverage, and approval gates before merge or deploy.'] },
      { title: 'Dev, Stage, and Prod by Approvals', image: '/images/github-actions/environments-approvals.svg', content: `GitHub Environments are the cleanest way to model dev, stage, and prod. Each environment can have its own secrets, wait timers, required reviewers, and deployment history. A practical pattern is automatic deployment to dev, gated promotion to stage, and strict approval for prod.\n\nThis keeps low-risk feedback fast while making production releases explicit and reviewable.`, keyPoints: ['Environment rules should reflect deployment risk.', 'Dev can be fast while prod stays protected.', 'Environment-scoped secrets reduce accidental leakage.', 'Approval history improves release traceability.'] },
      { title: 'Code Review by Actions and PR Checklist Validation', image: '/images/github-actions/review-coverage.svg', content: `Actions can enforce objective pull request rules before human review begins. Common checks include PR title format, linked issue references, required labels, changed-file policies, test success, and checklist completion through PR templates or body validation.\n\nThis does not replace code review. It raises the floor so reviewers spend time on architecture, correctness, and operational risk rather than missing basics.`, keyPoints: ['Automate objective review checks first.', 'Pair PR templates with workflow validation.', 'Use automation to reduce review noise.', 'Humans should focus on correctness, design, and risk.'] },
      { title: 'Code Coverage Checking', content: `Coverage checking is useful when treated as one quality signal among several. A workflow can run tests, publish coverage artifacts, and fail the build if coverage drops below a threshold or if changed files are under-tested.\n\nHigh coverage does not guarantee correctness, but coverage reports make testing gaps visible and easier to discuss during review.`, code: `jobs:\n  coverage:\n    runs-on: ubuntu-latest\n    steps:\n    - uses: actions/checkout@v4\n    - run: npm ci\n    - run: npm test -- --coverage\n    - uses: actions/upload-artifact@v4\n      with:\n        name: coverage-report\n        path: coverage`, codeLabel: 'Coverage Gate', keyPoints: ['Coverage is a signal, not proof of correctness.', 'Publish reports so reviewers can inspect testing impact.', 'Use thresholds that improve quality without blocking work arbitrarily.', 'Diff coverage can be more practical than global perfection.'] },
      { title: 'Checklist While PR Creation', content: `A strong PR checklist makes Actions more effective because it clarifies what the workflow should enforce and what the author must explain. Good checklist items include linked issue or task, testing done, screenshots or logs where relevant, rollout notes, breaking-change notes, and confirmation that secrets or config changes were handled safely.\n\nActions can verify some of these automatically, while the rest stay as explicit author responsibilities in the PR template.`, keyPoints: ['Link the PR to a task or issue.', 'State what was tested and how.', 'Include screenshots or logs when behavior changed.', 'Note rollout, migration, or secret-handling concerns explicitly.'] },
      { title: 'Best Practices for Learning GitHub Actions', content: `The fastest way to learn GitHub Actions is to build one real workflow end to end: PR validation, Docker build, Linux and Windows testing, a manual deployment input, an approval gate for production, and one PR automation rule such as coverage or checklist validation.\n\nUse this checklist for every workflow: keep YAML readable, choose the right trigger, keep permissions minimal, protect secrets, make PR checks fast, separate build from deployment, and automate objective review checks before asking humans to review.`, keyPoints: ['Learn Actions by building a real CI and deployment flow.', 'Master YAML, events, permissions, runners, and environments first.', 'Keep PR workflows fast and deployment workflows deliberate.', 'Workflow quality is part of code quality.'] }
    ]
  }
];
